delta = 0.1; % 信号模值限制
rho = 1; % ADMM算法参数
max_iter = 1000; % 最大迭代次数

% 初始化变量
x = randn(N, 1) + 1i*randn(N, 1); % 初始化复信号
y = zeros(N, 1);
z = zeros(N, 1);
u = zeros(N, 1);

% 主循环
for iter = 1:max_iter
    % 更新x
    x = (z - u) / (1 + 1/rho);

    % 更新z
    z = x + u;
    z = z / max(1, norm(z) / (1 + delta));

    % 更新y
    y = z - u;

    % 更新u
    u = u + x - z;
end

% 检查等式约束条件：0时刻的自相关函数模值为1
Rxx_0 = sum(x(1:N) .* conj(x(N:-1:1))); % 计算自相关函数在0时刻的模值
fprintf('0时刻的自相关函数模值为: %.4f\n', abs(Rxx_0));

% 绘制设计得到的信号及其自相关函数
